import React, { useState, useRef, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useApp } from '../context/AppContext';
import { useToast } from '../context/ToastContext';

const TIER_STYLE = {
  free:   { color: 'var(--mu)',  bg: 'rgba(148,163,184,.12)', label: 'FREE'   },
  growth: { color: 'var(--in2)', bg: 'rgba(99,102,241,.15)',  label: 'GROWTH' },
  prime:  { color: 'var(--go2)', bg: 'rgba(245,158,11,.18)',  label: 'PRIME'  },
};

export function VenueSelector() {
  const { allVenues, activeVenue, switchVenue } = useAuth();
  const { setTier } = useApp();
  const { showToast } = useToast();
  const [open, setOpen] = useState(false);
  const ref = useRef(null);

  // Close dropdown on outside click
  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  // Show even with 1 venue so user can see their active venue
  if (!allVenues || allVenues.length === 0) return null;

  const handleSwitch = (venueId) => {
    const v = allVenues.find(x => x.id === venueId);
    if (!v) return;
    switchVenue(venueId);
    setTier(v.tier || 'free');
    setOpen(false);
    showToast(`Switched to ${v.name} ✓`);
  };

  const ts = TIER_STYLE[activeVenue?.tier] || TIER_STYLE.free;

  return (
    <div ref={ref} style={{ position: 'relative', margin: '8px 12px 0' }}>
      {/* Trigger button */}
      <button
        onClick={() => setOpen(o => !o)}
        style={{
          width: '100%', padding: '9px 12px',
          background: open ? 'var(--s2)' : 'var(--s1)',
          border: `1px solid ${open ? 'var(--in)' : 'var(--b1)'}`,
          borderRadius: 'var(--r2)', cursor: 'pointer',
          display: 'flex', alignItems: 'center', gap: 9,
          transition: 'all .15s', fontFamily: 'inherit',
        }}
      >
        {/* Venue icon */}
        <div style={{
          width: 28, height: 28, borderRadius: 7, flexShrink: 0,
          background: 'linear-gradient(135deg,var(--in),var(--pu))',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontSize: 12, fontWeight: 700, color: '#fff',
        }}>
          {(activeVenue?.name || 'V').charAt(0)}
        </div>

        <div style={{ flex: 1, textAlign: 'left', minWidth: 0 }}>
          <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--tx)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            {activeVenue?.name || 'Select venue'}
          </div>
          <div style={{ fontSize: 10, color: 'var(--mu)', marginTop: 1 }}>
            {activeVenue?.location || ''}
          </div>
        </div>

        {/* Tier badge */}
        <span style={{ fontSize: 9, fontWeight: 700, padding: '2px 7px', borderRadius: 10, background: ts.bg, color: ts.color, flexShrink: 0 }}>
          {ts.label}
        </span>

        {/* Chevron */}
        <span style={{ color: 'var(--mu)', fontSize: 10, transition: 'transform .2s', transform: open ? 'rotate(180deg)' : 'rotate(0deg)', flexShrink: 0 }}>▾</span>
      </button>

      {/* Dropdown */}
      {open && (
        <div style={{
          position: 'absolute', top: 'calc(100% + 6px)', left: 0, right: 0,
          background: 'var(--bg3)', border: '1px solid var(--b2)',
          borderRadius: 'var(--r2)', boxShadow: '0 12px 40px rgba(0,0,0,.5)',
          zIndex: 50, overflow: 'hidden',
        }}>
          <div style={{ padding: '8px 12px 6px', fontSize: 10, color: 'var(--dim)', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '1px' }}>
            Your venues ({allVenues.length})
          </div>

          {allVenues.map((v) => {
            const isActive = v.id === activeVenue?.id;
            const s = TIER_STYLE[v.tier] || TIER_STYLE.free;
            return (
              <div
                key={v.id}
                onClick={() => handleSwitch(v.id)}
                style={{
                  display: 'flex', alignItems: 'center', gap: 10,
                  padding: '10px 12px', cursor: 'pointer',
                  background: isActive ? 'rgba(99,102,241,.1)' : 'transparent',
                  borderLeft: isActive ? '2px solid var(--in)' : '2px solid transparent',
                  transition: 'background .12s',
                }}
                onMouseEnter={e => { if (!isActive) e.currentTarget.style.background = 'var(--s1)'; }}
                onMouseLeave={e => { if (!isActive) e.currentTarget.style.background = 'transparent'; }}
              >
                <div style={{
                  width: 32, height: 32, borderRadius: 8, flexShrink: 0,
                  background: isActive
                    ? 'linear-gradient(135deg,var(--in),var(--pu))'
                    : 'var(--s2)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 13, fontWeight: 700, color: isActive ? '#fff' : 'var(--mu)',
                }}>
                  {v.name.charAt(0)}
                </div>

                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 13, fontWeight: isActive ? 600 : 400, color: isActive ? 'var(--tx)' : 'var(--tx2)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {v.name}
                    {isActive && <span style={{ marginLeft: 6, fontSize: 10, color: 'var(--in2)' }}>● Active</span>}
                  </div>
                  <div style={{ fontSize: 11, color: 'var(--mu)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{v.location}</div>
                </div>

                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 3, flexShrink: 0 }}>
                  <span style={{ fontSize: 9, fontWeight: 700, padding: '2px 7px', borderRadius: 10, background: s.bg, color: s.color }}>
                    {s.label}
                  </span>
                  <span style={{ fontSize: 10, color: v.nc_balance < 5000 ? 'var(--rd2)' : 'var(--mu)' }}>
                    {(v.nc_balance || 0).toLocaleString()} NC
                  </span>
                </div>
              </div>
            );
          })}

          {/* Add venue CTA */}
          <div style={{ padding: '8px 12px 10px', borderTop: '1px solid var(--b1)', marginTop: 4 }}>
            <button
              onClick={() => { setOpen(false); showToast('Contact support to add a new venue to your account'); }}
              style={{ width: '100%', padding: '7px', background: 'transparent', border: '1px dashed var(--b2)', borderRadius: 7, color: 'var(--mu)', fontSize: 12, cursor: 'pointer', fontFamily: 'inherit', transition: 'all .15s' }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = 'var(--in)'; e.currentTarget.style.color = 'var(--in2)'; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = 'var(--b2)';  e.currentTarget.style.color = 'var(--mu)'; }}
            >
              + Add another venue
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
